using System.Collections.Concurrent;

namespace sv_3016932017f04d1fb80ac14ecb25dc7d.Services;

/// <summary>
/// Singleton backing store that holds cart data keyed by session ID.
/// Survives circuit disposal so state persists across page navigations
/// in per-page interactivity mode.
/// </summary>
public class CartStore
{
    private readonly ConcurrentDictionary<string, List<CartItem>> _carts = new();

    public List<CartItem> GetItems(string sessionId)
    {
        return _carts.GetOrAdd(sessionId, _ => []);
    }

    public void Add(string sessionId, CartItem item)
    {
        var items = GetItems(sessionId);
        lock (items)
        {
            var existing = items.FirstOrDefault(i => i.Id == item.Id);
            if (existing is not null)
            {
                existing.Quantity += item.Quantity;
            }
            else
            {
                items.Add(new CartItem
                {
                    Id = item.Id,
                    Name = item.Name,
                    Price = item.Price,
                    Quantity = item.Quantity
                });
            }
        }
    }

    public void Remove(string sessionId, int itemId)
    {
        var items = GetItems(sessionId);
        lock (items)
        {
            items.RemoveAll(i => i.Id == itemId);
        }
    }

    public void Clear(string sessionId)
    {
        var items = GetItems(sessionId);
        lock (items)
        {
            items.Clear();
        }
    }
}

