toolArgs.file_text:
namespace sv_3016932017f04d1fb80ac14ecb25dc7d.Services;

/// <summary>
/// Scoped (per-circuit) service that wraps the singleton CartStore.
/// Components on the same page share this instance and react to OnChange.
/// On navigation, a new instance is created but reads the same backing data
/// via the session-keyed CartStore.
/// </summary>
public class CartState
{
    private readonly CartStore _store;
    private readonly string _sessionId;

    public CartState(CartStore store, IHttpContextAccessor httpContextAccessor)
    {
        _store = store;
        // CartSessionId is set by middleware before any component renders.
        // HttpContext.Items is used so the ID is available even on the very
        // first request (before the response cookie reaches the browser).
        _sessionId = httpContextAccessor.HttpContext?.Items["CartSessionId"] as string
            ?? Guid.NewGuid().ToString();
    }

    public IReadOnlyList<CartItem> Items
    {
        get
        {
            var items = _store.GetItems(_sessionId);
            lock (items)
            {
                return items.ToList();
            }
        }
    }

    public int Count => Items.Sum(i => i.Quantity);

    public decimal Total => Items.Sum(i => i.Price * i.Quantity);

    public event Action? OnChange;

    public void Add(CartItem item)
    {
        _store.Add(_sessionId, item);
        OnChange?.Invoke();
    }

    public void Remove(int itemId)
    {
        _store.Remove(_sessionId, itemId);
        OnChange?.Invoke();
    }

    public void Clear()
    {
        _store.Clear(_sessionId);
        OnChange?.Invoke();
    }
}

