@page "/products"
@rendermode InteractiveServer
@inject CartState Cart

<PageTitle>Products</PageTitle>

<h1>Products</h1>

<div class="row">
    @foreach (var product in products)
    {
        <div class="col-md-4 mb-4">
            <div class="card h-100">
                <div class="card-body d-flex flex-column">
                    <h5 class="card-title">@product.Name</h5>
                    <p class="card-text text-muted">@product.Description</p>
                    <p class="card-text fw-bold mt-auto">$@product.Price.ToString("F2")</p>
                    <button class="btn btn-primary" @onclick="() => AddToCart(product)">
                        Add to Cart
                    </button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private record Product(int Id, string Name, string Description, decimal Price);

    private readonly Product[] products =
    [
        new(1, "Wireless Headphones", "Noise-cancelling over-ear headphones", 49.99m),
        new(2, "Mechanical Keyboard", "RGB backlit with Cherry MX switches", 89.99m),
        new(3, "USB-C Hub", "7-in-1 adapter with HDMI and SD card reader", 34.99m),
        new(4, "Monitor Stand", "Adjustable aluminum desk stand", 29.99m),
        new(5, "Webcam HD", "1080p with built-in microphone", 59.99m),
        new(6, "Laptop Sleeve", "Water-resistant neoprene sleeve", 19.99m),
    ];

    private void AddToCart(Product product)
    {
        Cart.Add(new CartItem
        {
            Id = product.Id,
            Name = product.Name,
            Price = product.Price,
            Quantity = 1
        });
    }
}

@page "/cart"
@rendermode InteractiveServer
@inject CartState Cart
@implements IDisposable

<PageTitle>Cart</PageTitle>

<h1>Shopping Cart</h1>

@if (Cart.Items.Count == 0)
{
    <p class="text-muted">Your cart is empty.</p>
    <a href="products" class="btn btn-primary">Browse Products</a>
}
else
{
    <table class="table align-middle">
        <thead>
            <tr>
                <th>Product</th>
                <th>Price</th>
                <th>Quantity</th>
                <th>Subtotal</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in Cart.Items)
            {
                <tr>
                    <td>@item.Name</td>
                    <td>$@item.Price.ToString("F2")</td>
                    <td>@item.Quantity</td>
                    <td>$@((item.Price * item.Quantity).ToString("F2"))</td>
                    <td>
                        <button class="btn btn-danger btn-sm" @onclick="() => Cart.Remove(item.Id)">
                            Remove
                        </button>
                    </td>
                </tr>
            }
        </tbody>
    </table>

    <div class="d-flex justify-content-between align-items-center mt-3">
        <h4 class="mb-0">Total: $@Cart.Total.ToString("F2")</h4>
        <button class="btn btn-warning" @onclick="Cart.Clear">Clear Cart</button>
    </div>
}

@code {
    protected override void OnInitialized()
    {
        Cart.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        Cart.OnChange -= StateHasChanged;
    }
}

