using sv_3016932017f04d1fb80ac14ecb25dc7d.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();

builder.Services.AddHttpContextAccessor();
builder.Services.AddSingleton<CartStore>();
builder.Services.AddScoped<CartState>();

var app = builder.Build();

// Assign a cart session cookie so each user gets an independent cart.
app.Use(async (context, next) =>
{
    if (!context.Request.Cookies.TryGetValue("CartSessionId", out var sessionId))
    {
        sessionId = Guid.NewGuid().ToString();
        context.Response.Cookies.Append("CartSessionId", sessionId, new CookieOptions
        {
            HttpOnly = true,
            SameSite = SameSiteMode.Strict,
            Expires = DateTimeOffset.UtcNow.AddDays(7)
        });
    }
    context.Items["CartSessionId"] = sessionId;
    await next();
});

// Configure the HTTP request pipeline.
