@if (CartState.Items.Count == 0)
{
    <p class="text-muted">Your cart is empty.</p>
    <a href="products" class="btn btn-primary">Browse Products</a>
}
else
{
    <table class="table align-middle">
        <thead>
            <tr>
                <th>Product</th>
                <th>Price</th>
                <th>Quantity</th>
                <th>Subtotal</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in CartState.Items)
            {
                <tr>
                    <td>@item.Name</td>
                    <td>$@item.Price.ToString("F2")</td>
                    <td>@item.Quantity</td>
                    <td>$@((item.Price * item.Quantity).ToString("F2"))</td>
                    <td>
                        <button class="btn btn-danger btn-sm" @onclick="() => CartState.Remove(item.Id)">
                            Remove
                        </button>
                    </td>
                </tr>
            }
        </tbody>
    </table>

    <div class="d-flex justify-content-between align-items-center mt-3">
        <h4 class="mb-0">Total: $@CartState.Total.ToString("F2")</h4>
        <button class="btn btn-warning" @onclick="CartState.Clear">Clear Cart</button>
    </div>
}

@code {
    protected override void OnInitialized()
    {
        CartState.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        CartState.OnChange -= StateHasChanged;
    }
